package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() {
    String name = "Apple";
    int quantity = 3;
    long priceInMicros = 2500000L; // 2.5 in normal units
    String currencyCode = "USD";

    LineItem lineItem = new LineItem(name, quantity, priceInMicros, currencyCode);

    String expected = String.format("(item: %s, qty: %s, price: %.2f %s)",
        name, quantity, priceInMicros / 1000000d, currencyCode);
    assertEquals(expected, lineItem.toString());
  }
}
